var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`INO_COLLABO_NULL_NULL`,text:{KOREA:`환영 받기는 글렀다고 생각했는데, 대범한 구석이 있네.`,JPN:`あら、歓迎してくれるの？　大胆ね。`,ENG:`I thought I was long past being welcomed. You're bolder than I thought you were.`,TWN:`I thought I was long past being welcomed. You're bolder than I thought you were.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INO_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`INO_COLLABO_NULL_NULL`,text:{KOREA:`다른 쓰레기들에 비하면 한가닥 한다고 뻐기고 싶어진 거야?`,JPN:`他のクズに比べればマシだって思い込んでるの？`,ENG:`What is this? Do you want to brag about being the best among the lowlife trash?`,TWN:`What is this? Do you want to brag about being the best among the lowlife trash?`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INO_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`INO_COLLABO_NULL_NULL`,text:{KOREA:`후훗, 가벼운 농담이야. 진지하게 받아들이지 마.`,JPN:`ふふっ、真に受けちゃった？　かわいいじゃない。`,ENG:`Fu fuu, just joking. Don't take it seriously.`,TWN:`Fu fuu, just joking. Don't take it seriously.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INO_COLLABO_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`INO_COLLABO_NULL_NULL`,text:{KOREA:`네가 방금 꺼낸 그 얘기 때문에 흥미가 더 커졌거든.`,JPN:`アンタがさっき切り出した話のせいで興味が湧いちゃったんだもの。`,ENG:`Your comment from just before caught my attention.`,TWN:`Your comment from just before caught my attention.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INO_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`INO_COLLABO_NULL_NULL`,text:{KOREA:`조금만 늦었어도 김 샐 뻔했는데, 아쉽게 됐네.`,JPN:`残念。少しでも遅れたら興ざめだったわ。`,ENG:`I was very close to getting disheartened. How unfortunate.`,TWN:`I was very close to getting disheartened. How unfortunate.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INO_COLLABO_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`INO_COLLABO_NULL_NULL`,text:{KOREA:`상관없어. 원래 연주란 건 강약이 있어야 할 맛이 생기잖아?`,JPN:`関係ないわ。もともと演奏ってのは強弱がなきゃ面白くないじゃない？`,ENG:`It doesn’t matter. There's always dynamics in playing, no?`,TWN:`It doesn’t matter. There's always dynamics in playing, no?`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INO_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`INO_COLLABO_NULL_NULL`,text:{KOREA:`그러니 멀뚱멀뚱 앉아 있지 말고 목이 째지게 환호할 준비나 해.`,JPN:`ぼんやり座ってないで、歓声を上げる準備でもしな。`,ENG:`Don't just sit around, be prepared to cheer with everything you've got.`,TWN:`Don't just sit around, be prepared to cheer with everything you've got.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INO_COLLABO_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`INO_COLLABO_NULL_NULL`,text:{KOREA:`떠나는 여자 붙잡고 가지 말라 했으면, 그 정도 성의는 보여 줘야 하지 않겠어?`,JPN:`離れていく女を捕まえたいなら、ある程度の誠意は見せないとね？`,ENG:`If you're clinging over a woman who's leaving, isn't that the least you can do?`,TWN:`If you're clinging over a woman who's leaving, isn't that the least you can do?`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INO_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};